class Stack {
private:
    std::vector<int> data;
public:
    void push(int value) { data.push_back(value); }
    int pop() {
        if (data.empty()) throw std::runtime_error("stack is empty");
        int value = data.back();
        data.pop_back();
        return value;
    }
    int peek() const {
        if (data.empty()) throw std::runtime_error("stack is empty");
        return data.back();
    }
};

