void push(Node** head, int value) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->value = value;
    node->next = *head;
    *head = node;
}

int pop(Node** head) {
    if (*head == NULL) return -1;
    Node* temp = *head;
    int value = temp->value;
    *head = temp->next;
    free(temp);
    return value;
}

