class CircularQueue {
private:
    int data[8];
    int head = 0;
    int tail = 0;
    int size = 0;
public:
    bool enqueue(int value) {
        if (size == 8) return false;
        data[tail] = value;
        tail = (tail + 1) % 8;
        ++size;
        return true;
    }
    bool dequeue(int& value) {
        if (size == 0) return false;
        value = data[head];
        head = (head + 1) % 8;
        --size;
        return true;
    }
};

