#include <stdio.h>

typedef struct {
    int data[8];
    int head;
    int tail;
    int size;
} CircularQueue;

int enqueue(CircularQueue* q, int value) {
    if (q->size == 8) return 0;
    q->data[q->tail] = value;
    q->tail = (q->tail + 1) % 8;
    q->size++;
    return 1;
}

int dequeue(CircularQueue* q, int* out) {
    if (q->size == 0) return 0;
    *out = q->data[q->head];
    q->head = (q->head + 1) % 8;
    q->size--;
    return 1;
}

