def lps(p):
    f = [0] * len(p)
    i, j = 1, 0
    while i < len(p):
        if p[i] == p[j]:
            j += 1
            f[i] = j
            i += 1
        elif j:
            j = f[j - 1]
        else:
            i += 1
    return f

