void setThread(Node* cur, Node*& pre) {
  if (!cur) return;
  setThread(cur->left, pre);
  if (!cur->left) { cur->left = pre; cur->ltag = true; }
  if (pre && !pre->right) { pre->right = cur; pre->rtag = true; }
  pre = cur;
  setThread(cur->right, pre);
}

