std::vector<int> inorderThreaded(Node* root) {
  std::vector<int> out;
  Node* cur = root;
  while (cur && !cur->ltag && cur->left) cur = cur->left;
  while (cur) {
    out.push_back(cur->val);
    if (cur->rtag) cur = cur->right;
    else {
      cur = cur->right;
      while (cur && !cur->ltag && cur->left) cur = cur->left;
    }
  }
  return out;
}

