/* Use array plus sift-up and sift-down. */
  #include <stdio.h>
  #include <stdlib.h>

  #define MAX_HEAP_SIZE 100

  typedef struct {
      int data[MAX_HEAP_SIZE];
      int size;
  } MinHeap;

  void initHeap(MinHeap *heap) {
      heap->size = 0;
  }

  int parent(int i) { return (i - 1) / 2; }
  int left(int i) { return 2 * i + 1; }
  int right(int i) { return 2 * i + 2; }

  // swap two elements in the heap
  void swap(int *a, int *b) {
      int temp = *a;
      *a = *b;
      *b = temp;
  }

  //  sift up to maintain heap property
  void siftUp(MinHeap *heap, int i) {
      if (i == 0) return;
      int p = parent(i);
      if (heap->data[i] < heap->data[p]) {
          swap(&heap->data[i], &heap->data[p]);
          siftUp(heap, p);
      }
  }

  // sift down to maintain heap property
  void siftDown(MinHeap *heap, int i) {
      int l = left(i);
      int r = right(i);
      int smallest = i;

      if (l < heap->size && heap->data[l] < heap->data[smallest]) {
          smallest = l;
      }
      if (r < heap->size && heap->data[r] < heap->data[smallest]) {
          smallest = r;
      }

      if (smallest != i) {
          swap(&heap->data[i], &heap->data[smallest]);
          siftDown(heap, smallest);
      }
  }

  // insert an element into the heap
  int insert(MinHeap *heap, int val) {
      if (heap->size >= MAX_HEAP_SIZE) {
          printf("Heap is full!\n");
          return -1;
      }
      heap->data[heap->size] = val;
      siftUp(heap, heap->size);
      heap->size++;
      return 0;
  }

  // get the top element of the heap
  int extractTop(MinHeap *heap) {
      if (heap->size == 0) {
          printf("Heap is empty!\n");
          return -1;
      }
      int top = heap->data[0];
      heap->data[0] = heap->data[heap->size - 1];
      heap->size--;
      siftDown(heap, 0);
      return top;
  }

  int main() {
      MinHeap heap;
      initHeap(&heap);
      insert(&heap, 5);
      insert(&heap, 3);
      insert(&heap, 8);
      printf("Extracted top: %d\n", extractTop(&heap)); // output: 3
      return 0;
  }

