Map<String, Integer> dijkstra(Map<String, List<Edge>> graph, String source) {
    Map<String, Integer> dist = new HashMap<>();
    for (String node : graph.keySet()) dist.put(node, Integer.MAX_VALUE);
    dist.put(source, 0);
    PriorityQueue<String> pq = new PriorityQueue<>(Comparator.comparingInt(dist::get));
    pq.offer(source);
    while (!pq.isEmpty()) {
        String node = pq.poll();
        for (Edge e : graph.get(node)) {
            int candidate = dist.get(node) + e.w;
            if (candidate < dist.get(e.to)) {
                dist.put(e.to, candidate);
                pq.offer(e.to);
            }
        }
    }
    return dist;
}

