#include <queue>
#include <vector>

std::vector<int> bfsDistance(const std::vector<std::vector<int>>& g, int s) {
  std::vector<int> d(g.size(), -1);
  std::queue<int> q;
  d[s] = 0; q.push(s);
  while (!q.empty()) {
    int u = q.front(); q.pop();
    for (int v : g[u]) if (d[v] == -1) { d[v] = d[u] + 1; q.push(v); }
  }
  return d;
}

