import heapq
def dijkstra(graph, s):
    d = {s: 0}
    pq = [(0, s)]
    while pq:
        du, u = heapq.heappop(pq)
        if du != d.get(u, float('inf')):
            continue
        for v, w in graph.get(u, []):
            nd = du + w
            if nd < d.get(v, float('inf')):
                d[v] = nd
                heapq.heappush(pq, (nd, v))
    return d

