import heapq
def prim(graph):
    n = len(graph)
    vis = [False] * n
    pq = [(0, 0)]
    total = 0
    while pq:
        w, u = heapq.heappop(pq)
        if vis[u]:
            continue
        vis[u] = True
        total += w
        for v, c in graph[u]:
            if not vis[v]:
                heapq.heappush(pq, (c, v))
    return total

