void shellSort(std::vector<int>& arr) {
  int n = static_cast<int>(arr.size());
  for (int gap = n / 2; gap > 0; gap /= 2) {
    for (int i = gap; i < n; ++i) {
      int temp = arr[i], j = i;
      while (j >= gap && arr[j - gap] > temp) { arr[j] = arr[j - gap]; j -= gap; }
      arr[j] = temp;
    }
  }
}

