import heapq
def merge_runs(runs):
    pq = []
    out = []
    for i, run in enumerate(runs):
        if run:
            heapq.heappush(pq, (run[0], i, 0))
    while pq:
        v, ri, idx = heapq.heappop(pq)
        out.append(v)
        if idx + 1 < len(runs[ri]):
            heapq.heappush(pq, (runs[ri][idx + 1], ri, idx + 1))
    return out

