  void bubbleSort(std::vector<int>& arr) {
    for (int i = 0; i < static_cast<int>(arr.size()) - 1; ++i) {
      bool swapped = false;
      for (int j = 0; j < static_cast<int>(arr.size()) - i - 1; ++j) {
        if (arr[j] > arr[j + 1]) {
          std::swap(arr[j], arr[j + 1]);
          swapped = true;
        }
      }
      if (!swapped) break;
    }
  }

  int main() {
    std::vector<int> arr = {7, 3, 9, 2, 6};
    bubbleSort(arr);
    for (int x : arr) std::cout << x << " ";
    std::cout << std::endl;
    return 0;
  }

