  int partition(std::vector<int>& arr, int left, int right) {
    int pivot = arr[right];
    int i = left;
    for (int j = left; j < right; ++j) {
      if (arr[j] < pivot) {
        std::swap(arr[i], arr[j]);
        ++i;
      }
    }
    std::swap(arr[i], arr[right]);
    return i;
  }

  void quickSort(std::vector<int>& arr, int left, int right) {
    if (left >= right) return;
    int p = partition(arr, left, right);
    quickSort(arr, left, p - 1);
    quickSort(arr, p + 1, right);
  }

  int main() {
    std::vector<int> arr = {9, 3, 7, 1, 8, 2};
    quickSort(arr, 0, static_cast<int>(arr.size()) - 1);
    for (int x : arr) std::cout << x << " ";
    std::cout << std::endl;
    return 0;
  }

#include <iostream>
  #include <vector>

  void merge(std::vector<int>& arr, int left, int mid, int right) {
    std::vector<int> temp;
    int i = left, j = mid + 1;
    while (i <= mid && j <= right) {
      if (arr[i] <= arr[j]) temp.push_back(arr[i++]);
      else temp.push_back(arr[j++]);
    }
    while (i <= mid) temp.push_back(arr[i++]);
    while (j <= right) temp.push_back(arr[j++]);
    for (int k = 0; k < static_cast<int>(temp.size()); ++k) {
      arr[left + k] = temp[k];
    }
  }

  void mergeSort(std::vector<int>& arr, int left, int right) {
    if (left >= right) return;
    int mid = left + (right - left) / 2;
    mergeSort(arr, left, mid);
    mergeSort(arr, mid + 1, right);
    merge(arr, left, mid, right);
  }

  int main() {
    std::vector<int> arr = {6, 5, 12, 10, 9, 1};
    mergeSort(arr, 0, static_cast<int>(arr.size()) - 1);
    for (int x : arr) std::cout << x << " ";
    std::cout << std::endl;
    return 0;
  }

#include <iostream>
  #include <vector>

  void heapify(std::vector<int>& arr, int n, int i) {
    int largest = i;
    int left = 2 * i + 1;
    int right = 2 * i + 2;

    if (left < n && arr[left] > arr[largest]) largest = left;
    if (right < n && arr[right] > arr[largest]) largest = right;

    if (largest != i) {
      std::swap(arr[i], arr[largest]);
      heapify(arr, n, largest);
    }
  }

  void heapSort(std::vector<int>& arr) {
    int n = static_cast<int>(arr.size());
    for (int i = n / 2 - 1; i >= 0; --i) heapify(arr, n, i);
    for (int i = n - 1; i > 0; --i) {
      std::swap(arr[0], arr[i]);
      heapify(arr, i, 0);
    }
  }

  int main() {
    std::vector<int> arr = {16, 14, 10, 8, 7, 9, 3};
    heapSort(arr);
    for (int x : arr) std::cout << x << " ";
    std::cout << std::endl;
    return 0;
  }

#include <algorithm>
  #include <iostream>
  #include <vector>

  void countingSortByExp(std::vector<int>& arr, int exp) {
    std::vector<int> output(arr.size());
    int count[10] = {0};

    for (int x : arr) ++count[(x / exp) % 10];
    for (int i = 1; i < 10; ++i) count[i] += count[i - 1];
    for (int i = static_cast<int>(arr.size()) - 1; i >= 0; --i) {
      int digit = (arr[i] / exp) % 10;
      output[count[digit] - 1] = arr[i];
      --count[digit];
    }
    arr = output;
  }

  void radixSort(std::vector<int>& arr) {
    int maxVal = *std::max_element(arr.begin(), arr.end());
    for (int exp = 1; maxVal / exp > 0; exp *= 10) {
      countingSortByExp(arr, exp);
    }
  }

  int main() {
    std::vector<int> arr = {170, 45, 75, 90, 802, 24, 2, 66};
    radixSort(arr);
    for (int x : arr) std::cout << x << " ";
    std::cout << std::endl;
    return 0;
  }

#include <algorithm>
  #include <iostream>
  #include <vector>

  void bucketSort(std::vector<float>& arr) {
    int n = static_cast<int>(arr.size());
    std::vector<std::vector<float>> buckets(n);

    for (float x : arr) {
      int idx = static_cast<int>(x * n);
      if (idx == n) idx = n - 1;
      buckets[idx].push_back(x);
    }

    for (auto& bucket : buckets) std::sort(bucket.begin(), bucket.end());

    int pos = 0;
    for (const auto& bucket : buckets) {
      for (float x : bucket) arr[pos++] = x;
    }
  }

  int main() {
    std::vector<float> arr = {0.42f, 0.32f, 0.23f, 0.52f, 0.25f, 0.47f, 0.51f};
    bucketSort(arr);
    for (float x : arr) std::cout << x << " ";
    std::cout << std::endl;
    return 0;
  }

#include <fstream>
  #include <iostream>
  #include <queue>
  #include <string>
  #include <vector>

  struct Node {
    int value;
    int fileId;
    bool operator>(const Node& other) const {
      return value > other.value;
    }
  };

  int main() {
    std::vector<std::string> files = {"run1.txt", "run2.txt", "run3.txt"};
    std::vector<std::ifstream> ins(files.size());
    for (int i = 0; i < static_cast<int>(files.size()); ++i) {
      ins[i].open(files[i]);
    }

    std::priority_queue<Node, std::vector<Node>, std::greater<Node>> minHeap;
    for (int i = 0; i < static_cast<int>(ins.size()); ++i) {
      int x;
      if (ins[i] >> x) minHeap.push({x, i});
    }

    std::ofstream out("merged.txt");
    while (!minHeap.empty()) {
      Node cur = minHeap.top();
      minHeap.pop();
      out << cur.value << "
";

      int nextValue;
      if (ins[cur.fileId] >> nextValue) {
        minHeap.push({nextValue, cur.fileId});
      }
    }

    for (auto& f : ins) f.close();
    out.close();
    std::cout << "Merge completed to merged.txt" << std::endl;
    return 0;
  }
